import react, { useState, useMemo } from 'react';

const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
];

const datatable = ({ data }) => {
    const [sortConfig, setsortconfig] = useState({ key: null, direction: 'asc' });
    const [filtertext, setfiltertext] = useState('');

    const handleclick = (key) => {
        setsortconfig(prev => ({
            key,
            direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedandfiltereddata = useMemo(() => {
        let processed = [...data];

        if (filtertext) {
            processed = processed.filter(item =>
                item.name.toLowerCase().includes(filtertext.toLowerCase())
            );
        }

        if (sortconfig.key) {
            processed.sort((a, b) => {
                if (a[sortconfig.key] < b[sortconfig.key]) return sortconfig.direction === 'asc' ? -1 : 1;
                if (a[sortconfig.key] > b[sortconfig.key]) return sortconfig.direction === 'asc' ? 1 : -1;
                return 0;
            });
        }

        return processed;
    }, [data, sortconfig, filtertext]);

    return (
        <div>
            <input
                type="text"
                placeholder="filter by name"
                value={filtertext}
                onchang={e => setfiltertext(e.target.value)}
            />
            <table>
                <thead>
                    <tr>
                        <th onclick={() => handleclick('id')}>id {sortconfig.key === 'id' && (sortconfig.direction === 'asc' ? '↑' : '↓')}</th>
                        <th onclick={() => handleclick('name')}>name {sortconfig.key === 'name' && (sortconfig.direction === 'asc' ? '↑' : '↓')}</th>
